    reg_we_check[6] = 1'b0;
    reg_we_check[7] = fdata_we;
    reg_we_check[8] = fifo_ctrl_we;
    reg_we_check[9] = host_fifo_config_we;
    reg_we_check[10] = target_fifo_config_we;
    reg_we_check[11] = 1'b0;
    reg_we_check[12] = 1'b0;
